<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>
    <div class="modal d-block">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header theme-primary partition-full  d-flex">
                    <h4 class="modal-title">{{ $t('Update') }}</h4>
                    <span class="user-guide">
                        <a class="ancuserguide text-white" data-toggle="collapse" href="#collapseReplyUG" role="button" aria-expanded="false" aria-controls="collapseExample"> <em class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}</a>
                        <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                            <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                <div class="con" v-html="$t('RateScheduleBulckUpdate')"></div>
                            </div>
                        </div>
                    </span>
                    <button type="button" class="close" v-on:click="Close">
                        <em class="fa fa-times" aria-hidden="true"></em>
                    </button>
                </div>
                <div class="modal-body">
                    <dynamic-form 
                        lang="en" 
                        ref="ResourceRate" 
                        :buttons="buttons" 
                        :schema="FormSchema" 
                        v-on:OnSubmit="onSubmit" 
                        :mandatorytext='MandatoryString'
                    ></dynamic-form>
                </div>
            </div>
        </div>
    </div>
</div>
</template>

<script>
import DataService from '../../services/DataService';
export default {
    props: {
        EditData: {
            type: Array,
            required: false,
        },
    },
    data() {
        return {
            isLoading: false,
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            companyId: null,
            userId: null,
            PageSize: 100,
            PageNumber: 1,
            searchCondition: '',
            GroupNewData: [],
            UtiltityNames: [],
            StateNames: [],
            WorkCodes: [],
            StatusData: [],
            FormSchema: [{
                layoutType: "four",
                Data: [
                    {
                        astype: "toggleField",
                        label: this.$t('Want to Update Rate'),
                        name: "WantToUpdateRate",
                        value: false,
                        placeholder: "",
                        config: {
                            onChange: this.onRateToggleChange
                        },
                        visibility: true
                    },
                    {
                        astype: "NumericField",
                        label: this.$t('Rate'),
                        name: "Rate",
                        value: "",
                        placeholder: this.$t('Enter Rate'),
                        validationRules: {}, // Initially no validation
                        config: {
                            options: [],
                        },
                        visibility: true,
                        disabled: true,
                    },
                    {
                        astype: "toggleField",
                        label: this.$t('Want to Update End Date'),
                        name: "WantToUpdateEndDate",
                        value: false,
                        placeholder: "",
                        config: {
                            onChange: this.onEndDateToggleChange
                        },
                        visibility: true
                    },
                    {
                        astype: "DateField",
                        label: this.$t('End Date (M/D/YYYY)'),
                        name: "EndDate",
                        value: '',
                        visibility: true,
                        placeholder: this.$t('EndDate'),
                        config: {
                            format: "MM/DD/YYYY"
                        },
                        validationRules: {}, // Initially no validation
                        visibility: true,
                        disabled: true,
                    },
                ]
            }],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Update",
                    isVisible: true,
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close,
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        
        if (vm.EditData && vm.EditData.length > 0) {
            vm.FormSchema[0].Data[1].value = vm.EditData[0].AMOUNT || '';
            vm.FormSchema[0].Data[3].value = vm.EditData[0].END_DATE || '';
        }
    },
    methods: {
        onRateToggleChange(isEnabled) {
            const vm = this;
            
            vm.FormSchema[0].Data[1].disabled = !isEnabled;
            
            if (isEnabled) {
                vm.FormSchema[0].Data[1].validationRules = {
                    "required": true
                };
            } else {
                vm.FormSchema[0].Data[1].validationRules = {};
                vm.FormSchema[0].Data[1].value = '';
            }
        },

        onEndDateToggleChange(isEnabled) {
            const vm = this;
            
            vm.FormSchema[0].Data[3].disabled = !isEnabled;
            
            if (isEnabled) {
                vm.FormSchema[0].Data[3].validationRules = {
                    "required": true
                };
            } else {
                vm.FormSchema[0].Data[3].validationRules = {};
                vm.FormSchema[0].Data[3].value = '';
            }
        },

       onSubmit(formfields, val) {
    var vm = this;
    debugger;
    
    // Check which fields are enabled
    const isRateEnabled = !vm.FormSchema[0].Data[1].disabled;
    const isEndDateEnabled = !vm.FormSchema[0].Data[3].disabled;
    
    // If both fields are disabled (no toggle selected)
    if (!isRateEnabled && !isEndDateEnabled) {
        // Temporarily enable both fields and set validation
        const originalRateDisabled = vm.FormSchema[0].Data[1].disabled;
        const originalEndDateDisabled = vm.FormSchema[0].Data[3].disabled;
        const originalRateValidation = vm.FormSchema[0].Data[1].validationRules;
        const originalEndDateValidation = vm.FormSchema[0].Data[3].validationRules;
        
        // Enable fields and set validation
        vm.FormSchema[0].Data[1].disabled = false;
        vm.FormSchema[0].Data[1].validationRules = { "required": true };
        
        vm.FormSchema[0].Data[3].disabled = false;
        vm.FormSchema[0].Data[3].validationRules = { "required": true };
        
        // Reset the form to trigger validation
        vm.$nextTick(() => {
            // The dynamic-form will automatically show validation errors
            
            // Restore original states after a delay
            setTimeout(() => {
                vm.FormSchema[0].Data[1].disabled = originalRateDisabled;
                vm.FormSchema[0].Data[1].validationRules = originalRateValidation;
                
                vm.FormSchema[0].Data[3].disabled = originalEndDateDisabled;
                vm.FormSchema[0].Data[3].validationRules = originalEndDateValidation;
            }, 100);
        });
        
        return;
    }
    
    let hasError = false;
    
    if (isRateEnabled) {
        const rateValue = formfields.Rate || vm.FormSchema[0].Data[1].value;
        if (!rateValue && rateValue !== 0) {
            hasError = true;
        }
    }
    
    if (isEndDateEnabled) {
        const endDateValue = formfields.EndDate || vm.FormSchema[0].Data[3].value;
        if (!endDateValue) {
            hasError = true;
        }
    }
    
    if (hasError) {
        return;
    }
    
    var objData = {
        RateScheduleId: vm.EditData.map(x => x.RATE_SCHEDULE_ID).join(","),
        ClientId: vm.EditData.length > 0 ? vm.EditData[0].CLIENT_ID : null,
       Rate: isRateEnabled ? (formfields.Rate || vm.FormSchema[0].Data[1].value || '') : '',
        EndDate: isEndDateEnabled ? (formfields.EndDate || vm.FormSchema[0].Data[3].value || null) : null // Send null instead of empty string
    };
    
    debugger;
    
    // Convert to string for API
    var obj = JSON.stringify(objData);
    
    DataService.BulkUpdateRate(obj).then(response => {
          if (response.data != null) {
                        const Result = JSON.parse(response.data)[0];
                        if (parseInt(Result.RESULT) === 1) {
                            vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('RateSchedule')]), "success", true, vm.$t("Alert"));
                            vm.Close();
                        } 
                        else if (parseInt(Result.RESULT) === -2) {
                            vm.ShowAlert(vm.$t('OverlapRecordsUpdateRates', [vm.$t('RateSchedule')]), "warning", true, vm.$t("Alert"));
                            vm.Close();
                        }
                        else if (parseInt(Result.RESULT) === -3) {
                            vm.ShowAlert(vm.$t('OverlapDateRangeForUpdateRates', [vm.$t('RateSchedule')]), "warning", true, vm.$t("Alert"));
                            vm.Close();
                        }
                        else {
                            vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));
                        }
                    }
    }).catch(error => {
        vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));
    });
},
        
        Close: async function () {
            await this.$parent.FetchData();
            this.$parent.isBulkUpdateRate = false;
        }
    }
}
</script>